                  <script>
window.addEventListener('message', (event) => {
	if (typeof event.data !== 'string') return;

	if (event.data.includes('set-comment-editor-height')) {
		const height = event.data.split(' ')[1];

		const frames = document.querySelectorAll(
			'.single_comment-frame, .commentFrame'
		);

		for (const frame of frames) {
			if (frame.contentWindow === event.source) {
				frame.style.height = height;
				break;
			}
		}
	}
});
</script>

























                  <script>

let wait = (function() {

  let SELF = {
    Until,
  };

  function Until(stateCheckCallback, delayMs=100, timeoutMs=null, initialDelayMs=0) {

    let useTimeout = timeoutMs !== null;
    delayMs = delayMs ?? 100;

    return new Promise((resolve, reject) => {

      let interval;

      function checkFunction() {
        let shouldResolve = stateCheckCallback();

        timeoutMs -= delayMs;

        if (shouldResolve) {
          window.clearInterval(interval);
          resolve();
        } else if (useTimeout && timeoutMs <= 0) {
          window.clearInterval(interval);
          reject();
        }
      }

      window.setTimeout(() => {
        checkFunction();
        interval = window.setInterval(checkFunction, delayMs);
      }, initialDelayMs);

    });

  }

  return SELF;

})();

</script>

























