                  <script>
(async function () {

    // v0.4

    let $ = document.querySelector.bind(document);
    let $$ = document.querySelectorAll.bind(document);

    await wait.Until(() => $('._app').dataset.isReady)

    const dataBlogId = $('._dataBlogId')?.textContent;
    const dataPostId = $('._dataPostId')?.textContent;
    const BLOG_ID = dataBlogId || $('head link[rel="service.post"]')?.href.split('feeds/')[1].split('/')[0];
    const POST_ID = dataPostId || Array.from($$('head link[type="application/atom+xml"]')).find(e => e.href.includes('comments/default'))?.href.split('feeds/')[1].split('/')[0];
    const API_KEY = '';

    if (!POST_ID) {
        console.info('No post ID provided.')
        return;
    }

    const MAX_TOP = 5;
    const MAX_REPLY = 3;

    let allComments = [];
    let topOffset = 0;
    const replyOffsetMap = {};

    function fetchAllComments(pageToken = '', acc = []) {
        const fields = 'items(id,inReplyTo(id),published,content,author(displayName,image/url)),nextPageToken';
        const url = `https://www.googleapis.com/blogger/v3/blogs/${BLOG_ID}/posts/${POST_ID}/comments?key=${API_KEY}&fetchBodies=true&fields=${fields}${pageToken ? '&pageToken=' + pageToken : ''}`;
        return fetch(url)
            .then(res => res.json())
            .then(data => {
                const items = data.items || [];
                acc.push(...items);
                if (data.nextPageToken) {
                    return fetchAllComments(data.nextPageToken, acc);
                } else {
                    return acc;
                }
            });
    }

    function getAvatarHtml(author) {
        const hasImage = author.image && author.image.url && !author.image.url.includes('blank.gif');
        if (hasImage) {
            // YouTube uses small thumbnails, 40x40 is standard
            const imgUrl = author.image.url.replace('/s1600/', '/s40-c/');
            return `<img src="${imgUrl}" class="avatar" alt="${author.displayName}">`;
        }
        const initial = author.displayName.charAt(0).toUpperCase();
        return `<div class="avatar fallback">${initial}</div>`;
    }

    function render() {
        const container = $('._comments');
        container.innerHTML = '';

        const topComments = allComments
            .filter(c => !c.inReplyTo)
            .sort((a, b) => new Date(b.published) - new Date(a.published));

        const slice = topComments.slice(0, topOffset + MAX_TOP);

        // top level comment
        // #comment
        slice.forEach(parent => {
            const div = document.createElement('div');
            div.className = 'comment';
            div.innerHTML = commentTemplate(parent, true);
            container.appendChild(div);
            renderReplies(parent.id, div.querySelector('.replies'));
        });

        if (topOffset + MAX_TOP < topComments.length) {
            const more = document.createElement('button');
            more.className = 'btn';
            more.textContent = 'Read older comments';
            more.onclick = () => {
                topOffset += MAX_TOP;
                render();
            };
            container.appendChild(more);
        }

        // reply top level
        // #reply
        container.querySelectorAll('.reply-btn').forEach(btn => {
            btn.onclick = () => {
                let originalFormSrc = $('._dataPostCommentFormIframeSrc')?.textContent;
                let parentID = btn.dataset.id;

                if (!originalFormSrc) {
                    alert('Cannot post reply. Original form URL is required.')
                    return;
                }

                // hide others
                Array.from($$('._replyFormDiv')).forEach(e => e.innerHTML = '')

                let parentId = btn.dataset.id;
                let div = $(`._replyFormDiv[data-id="${parentId}"]`);
                div.innerHTML = `<iframe class="commentFrame" src="${originalFormSrc}&parentID=${parentID}">`
            };
        });
    }

    const commentTemplate = (item, isRoot) => `
        <div class="commentItem">
            ${getAvatarHtml(item.author)}
            <div class="commentBody">
                <div class="commentHead">
                    <span class="author">${item.author.displayName}</span>
                    <span class="meta">${new Date(item.published).toLocaleDateString()}</span>
                </div>
                <div class="content">${item.content}</div>
                <div class="commentActions">
                    <button class="reply-btn" data-id="${item.id}">Reply</button>
                </div>
                <div class="replyFormDiv _replyFormDiv" data-id="${item.id}"></div>
            </div>
        </div>
        <div class="replies" id="replies-${item.id}"></div>
    `;

    function renderReplies(parentId, container) {
        const replies = allComments
            .filter(c => c.inReplyTo && c.inReplyTo.id === parentId)
            .sort((a, b) => new Date(a.published) - new Date(b.published));

        replies.forEach(reply => {
            const div = document.createElement('div');
            div.className = 'comment';
            div.innerHTML = commentTemplate(reply, false);
            container.appendChild(div);

            const nested = div.querySelector('.replies');
            renderReplies(reply.id, nested);
        });
    }


    fetchAllComments().then(data => {
        allComments = data;
        render();
    });

})();
</script>

























                  <script>
(async function () {

await new Promise(resolve => window.setTimeout(resolve, 500));

  const currentUrl = new URL(window.location.href);
  const currentParams = currentUrl.searchParams;
  const hasM1 = currentParams.has("m") && currentParams.get("m") === "1";

  if (!hasM1) return; // Exit if m=1 is not present in the current URL

  document.querySelectorAll("a").forEach((link) => {
    const linkUrl = new URL(link.href, window.location.origin);

    if (linkUrl.origin === window.location.origin) { // Internal link check
      if (!linkUrl.searchParams.has("m")) {
        linkUrl.searchParams.set("m", "1");
      }
      link.href = linkUrl.toString();
    }
  });
})();
</script>
































