                  <style>
:root {
  --yt-text-primary: #0f0f0f;
  --yt-text-secondary: #606060;
  --yt-line-color: #e5e5e5; /* Light gray for the thread line */
}

.comment {
  position: relative;
  margin-bottom: 0.5rem;
}

.commentItem {
  display: flex;
  gap: 12px;
  padding: 8px 0;
  position: relative;
  z-index: 2; /* Keep content above the line */
}

.avatar {
  width: 40px;
  height: 40px;
  border-radius: 50%;
  flex-shrink: 0;
  object-fit: cover;
  background: #eee;
}

/* The Vertical Threading Line */
/* This attaches to the 'replies' container */
.replies {
  margin-left: 20px; /* Half of the 40px avatar */
  padding-left: 32px; /* Space for the reply content */
  border-left: 2px solid var(--yt-line-color);
  margin-top: -5px;
  margin-bottom: 10px;
}

/* Optional: Make the line change color on hover to show active thread */
.replies:hover {
  border-left-color: #065fd4;
}

.commentBody {
  flex-grow: 1;
}

.author {
  font-size: 13px;
  font-weight: 600;
  color: var(--yt-text-primary);
  margin-right: 8px;
}

.meta {
  font-size: 12px;
  color: var(--yt-text-secondary);
}

.content {
  font-size: 14px;
  line-height: 1.4;
  margin: 4px 0;
}

.reply-btn {
  background: none;
  border: none;
  color: var(--yt-text-primary);
  font-size: 12px;
  font-weight: 600;
  cursor: pointer;
  padding: 8px 12px;
  border-radius: 18px;
  margin-left: -12px;
}

.reply-btn:hover {
  background: #f2f2f2;
}

.commentFrame {
    width: 100%;
    border: 1px solid #eee;
    border-radius: 8px;
}
</style>
































